function baseLayer(cx, cy, s, palette, shape = "oval") {
  const warningGlow = palette.accent === "#dc2626"
    ? `<ellipse class="asset-warning-glow" cx="${fmt(cx)}" cy="${fmt(cy + 1 * s)}" rx="${fmt(59 * s)}" ry="${fmt(47 * s)}" fill="${palette.accent}" opacity="${fmt(palette.glowOpacity)}" filter="url(#asset-warning-glow)"/>`
    : "";
  const body = shape === "panel"
    ? `<rect class="asset-soft-body-gradient" x="${fmt(cx - 52 * s)}" y="${fmt(cy - 37 * s)}" width="${fmt(104 * s)}" height="${fmt(74 * s)}" rx="${fmt(17 * s)}" fill="${palette.secondary}" opacity="${fmt(palette.surfaceOpacity)}"/><rect class="asset-body-depth-overlay" x="${fmt(cx - 48 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(96 * s)}" height="${fmt(70 * s)}" rx="${fmt(16 * s)}" fill="url(#asset-body-depth)" opacity="${fmt(palette.depthOpacity)}"/>`
    : `<ellipse class="asset-soft-body-gradient" cx="${fmt(cx)}" cy="${fmt(cy)}" rx="${fmt(55 * s)}" ry="${fmt(43 * s)}" fill="${palette.secondary}" opacity="${fmt(palette.surfaceOpacity + 0.04)}"/><ellipse class="asset-body-depth-overlay" cx="${fmt(cx)}" cy="${fmt(cy - 2 * s)}" rx="${fmt(51 * s)}" ry="${fmt(39 * s)}" fill="url(#asset-body-depth)" opacity="${fmt(palette.depthOpacity)}"/>`;
  return [
    warningGlow,
    `<ellipse class="asset-contact-shadow" cx="${fmt(cx)}" cy="${fmt(cy + 45 * s)}" rx="${fmt(48 * s)}" ry="${fmt(10.5 * s)}" fill="#0f172a" opacity="${fmt(palette.contactOpacity)}" filter="url(#asset-contact-shadow)"/>`,
    body
  ].join("");
}

function cellAsset(cx, cy, s, palette, options = {}) {
  const cellKind = options.abnormal ? "tumor" : options.arms ? "macrophage" : options.receptors === "tcr" ? "t" : options.receptors === "bcr" ? "b" : "immune";
  const bodyScale = cellKind === "t" ? 0.9 : cellKind === "b" ? 0.95 : cellKind === "macrophage" ? 1.08 : cellKind === "tumor" ? 1.16 : 1;
  const membrane = organicPath(cx + (cellKind === "macrophage" ? 2 * s : 0), cy, s * bodyScale, options.lobes ?? 7, options.abnormal ? 1.18 : cellKind === "t" ? 0.86 : 1);
  const nucleus = options.nucleus === "bean"
    ? `<path d="${beanPath(cx - 12 * s, cy + 1 * s, s * 1.06)}" fill="${palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(1.45 * s)}"/>`
    : options.nucleus === "large"
      ? `<ellipse cx="${fmt(cx - 12 * s)}" cy="${fmt(cy - 1 * s)}" rx="${fmt(18 * s)}" ry="${fmt(15 * s)}" fill="${palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(1.5 * s)}"/><ellipse cx="${fmt(cx + 9 * s)}" cy="${fmt(cy + 13 * s)}" rx="${fmt(8 * s)}" ry="${fmt(6 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}" opacity="0.9"/>`
      : `<ellipse cx="${fmt(cx - 11 * s)}" cy="${fmt(cy)}" rx="${fmt((cellKind === "t" ? 11 : 13) * s)}" ry="${fmt((cellKind === "t" ? 10 : 12) * s)}" fill="${palette.secondary}" stroke="${palette.stroke}" stroke-width="${fmt(1.45 * s)}"/>`;
  const granules = scatterDots(cx + 15 * s, cy + 1 * s, s, options.granules ?? 5, palette.accent, 0.82);
  const cytoDetail = cellKind === "macrophage"
    ? `<path d="M${fmt(cx - 4 * s)},${fmt(cy + 18 * s)} C${fmt(cx + 11 * s)},${fmt(cy + 8 * s)} ${fmt(cx + 33 * s)},${fmt(cy + 12 * s)} ${fmt(cx + 39 * s)},${fmt(cy + 1 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(2.1 * s)}" stroke-linecap="round" opacity="0.58"/><circle cx="${fmt(cx + 13 * s)}" cy="${fmt(cy + 19 * s)}" r="${fmt(5.2 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}" opacity="0.86"/>`
    : cellKind === "tumor"
      ? `<path d="M${fmt(cx - 31 * s)},${fmt(cy + 8 * s)} C${fmt(cx - 13 * s)},${fmt(cy - 5 * s)} ${fmt(cx + 13 * s)},${fmt(cy + 2 * s)} ${fmt(cx + 29 * s)},${fmt(cy - 12 * s)} M${fmt(cx - 23 * s)},${fmt(cy + 24 * s)} C${fmt(cx - 6 * s)},${fmt(cy + 11 * s)} ${fmt(cx + 22 * s)},${fmt(cy + 20 * s)} ${fmt(cx + 35 * s)},${fmt(cy + 7 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.75 * s)}" stroke-linecap="round" opacity="0.5"/><circle cx="${fmt(cx + 2 * s)}" cy="${fmt(cy - 20 * s)}" r="${fmt(3.6 * s)}" fill="${palette.accent}" opacity="0.7"/>`
      : cellKind === "b"
        ? `<path d="M${fmt(cx - 31 * s)},${fmt(cy + 12 * s)} C${fmt(cx - 15 * s)},${fmt(cy + 3 * s)} ${fmt(cx + 3 * s)},${fmt(cy + 13 * s)} ${fmt(cx + 19 * s)},${fmt(cy + 2 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.8 * s)}" stroke-linecap="round" opacity="0.56"/><ellipse cx="${fmt(cx + 7 * s)}" cy="${fmt(cy - 18 * s)}" rx="${fmt(7 * s)}" ry="${fmt(4 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.05 * s)}" opacity="0.86"/>`
        : cellKind === "t"
          ? `<path d="M${fmt(cx - 27 * s)},${fmt(cy + 14 * s)} C${fmt(cx - 9 * s)},${fmt(cy + 3 * s)} ${fmt(cx + 11 * s)},${fmt(cy + 13 * s)} ${fmt(cx + 28 * s)},${fmt(cy + 1 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.8 * s)}" stroke-linecap="round" opacity="0.54"/><circle cx="${fmt(cx + 8 * s)}" cy="${fmt(cy - 17 * s)}" r="${fmt(3.4 * s)}" fill="${palette.accent}" opacity="0.76"/>`
          : `<path d="M${fmt(cx - 27 * s)},${fmt(cy + 13 * s)} C${fmt(cx - 9 * s)},${fmt(cy + 1 * s)} ${fmt(cx + 11 * s)},${fmt(cy + 13 * s)} ${fmt(cx + 29 * s)},${fmt(cy)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.85 * s)}" stroke-linecap="round" opacity="0.55"/><ellipse cx="${fmt(cx + 4 * s)}" cy="${fmt(cy - 18 * s)}" rx="${fmt(6.5 * s)}" ry="${fmt(4 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.05 * s)}" opacity="0.86"/>`;
  const membraneDetails = cellKind === "t"
    ? surfaceSpikes(cx + 40 * s, cy - 3 * s, s, palette.accent, "tcr")
    : cellKind === "b"
      ? surfaceSpikes(cx + 36 * s, cy - 6 * s, s, palette.accent, "bcr")
      : cellKind === "macrophage"
        ? `<path d="M${fmt(cx - 42 * s)},${fmt(cy - 16 * s)} C${fmt(cx - 65 * s)},${fmt(cy - 33 * s)} ${fmt(cx - 72 * s)},${fmt(cy - 1 * s)} ${fmt(cx - 51 * s)},${fmt(cy + 8 * s)} M${fmt(cx + 39 * s)},${fmt(cy + 9 * s)} C${fmt(cx + 68 * s)},${fmt(cy + 2 * s)} ${fmt(cx + 66 * s)},${fmt(cy + 33 * s)} ${fmt(cx + 39 * s)},${fmt(cy + 27 * s)} M${fmt(cx - 19 * s)},${fmt(cy + 36 * s)} C${fmt(cx - 39 * s)},${fmt(cy + 55 * s)} ${fmt(cx + 2 * s)},${fmt(cy + 61 * s)} ${fmt(cx + 8 * s)},${fmt(cy + 37 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(2.35 * s)}" stroke-linecap="round"/>`
        : cellKind === "tumor"
          ? `<path d="M${fmt(cx - 40 * s)},${fmt(cy - 30 * s)} l${fmt(10 * s)},${fmt(-10 * s)} M${fmt(cx + 34 * s)},${fmt(cy - 19 * s)} l${fmt(12 * s)},${fmt(-8 * s)} M${fmt(cx + 39 * s)},${fmt(cy + 19 * s)} l${fmt(14 * s)},${fmt(4 * s)} M${fmt(cx - 34 * s)},${fmt(cy + 26 * s)} l${fmt(-13 * s)},${fmt(7 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.2 * s)}" stroke-linecap="round" opacity="0.78"/>`
          : surfaceSpikes(cx + 33 * s, cy - 5 * s, s, palette.accent, "immune");
  const lineageDetail = cellKind === "b"
    ? `<path d="M${fmt(cx + 13 * s)},${fmt(cy + 23 * s)} v${fmt(17 * s)} M${fmt(cx + 13 * s)},${fmt(cy + 30 * s)} l${fmt(-11 * s)},${fmt(-10 * s)} M${fmt(cx + 13 * s)},${fmt(cy + 30 * s)} l${fmt(11 * s)},${fmt(-10 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx + 37 * s)}" cy="${fmt(cy + 27 * s)}" r="${fmt(4 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}"/>`
    : cellKind === "t"
      ? `<path d="M${fmt(cx + 24 * s)},${fmt(cy + 21 * s)} h${fmt(25 * s)} M${fmt(cx + 37 * s)},${fmt(cy + 11 * s)} v${fmt(20 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.1 * s)}" stroke-linecap="round" opacity="0.82"/>`
      : cellKind === "macrophage"
        ? `<circle cx="${fmt(cx + 22 * s)}" cy="${fmt(cy - 13 * s)}" r="${fmt(8 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}" opacity="0.86"/><path d="M${fmt(cx + 16 * s)},${fmt(cy - 13 * s)} h${fmt(12 * s)} M${fmt(cx + 22 * s)},${fmt(cy - 19 * s)} v${fmt(12 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round"/>`
        : cellKind === "tumor"
          ? `<path d="M${fmt(cx + 18 * s)},${fmt(cy - 28 * s)} l${fmt(9 * s)},${fmt(16 * s)} h${fmt(-18 * s)} Z" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}"/><circle cx="${fmt(cx + 18 * s)}" cy="${fmt(cy + 20 * s)}" r="${fmt(4.5 * s)}" fill="${palette.accent}" opacity="0.85"/>`
          : "";
  const receptors = options.receptors === "tcr"
    ? receptorMarks(cx + 39 * s, cy - 8 * s, s, palette.accent, "plus")
    : options.receptors === "bcr"
      ? receptorMarks(cx + 36 * s, cy - 10 * s, s, palette.accent, "fork")
      : "";
  const badge = options.badge ? `<circle cx="${fmt(cx + 31 * s)}" cy="${fmt(cy - 24 * s)}" r="${fmt(10 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}"/><text x="${fmt(cx + 31 * s)}" y="${fmt(cy - 20.5 * s)}" text-anchor="middle" font-family="Inter, Arial, sans-serif" font-size="${fmt(9 * s)}" font-weight="800" fill="${palette.accent}">${escapeXml(options.badge)}</text>` : "";
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)"><path d="${membrane}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.4 * s)}" stroke-linejoin="round"/><path d="${membrane}" fill="url(#asset-glass-highlight)" opacity="0.48"/><path d="${membrane}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.35 * s)}" opacity="0.56"/>${nucleus}${cytoDetail}${granules}${membraneDetails}${receptors}${lineageDetail}${badge}</g>${shine(cx - 20 * s, cy - 24 * s, s)}`;
}

