  const granules = [[-7, 20, 2.3], [9, 22, 2.7], [21, 14, 2.5], [27, -1, 2.2], [17, -17, 2.4], [-4, -26, 2], [-26, 16, 2.1], [34, 21, 1.9], [35, -15, 1.8]].map(([x, y, r], index) => `<circle class="asset-immune-granule" data-granule-index="${index}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" r="${fmt(r * s)}" fill="${palette.accent}" opacity="${fmt(index % 2 ? 0.55 : 0.74)}"/>`).join("");
