  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${membraneRuffles}<path class="asset-immune-cell-body" d="${body}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.3 * s)}"/><path class="asset-immune-cell-glass" d="${body}" fill="url(#asset-glass-highlight)" opacity="0.44"/><path class="asset-immune-cell-rim" d="${body}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.25 * s)}" opacity="0.56"/>${segmentedNucleus}${granules}${receptors}${badge}</g>${shine(cx - 21 * s, cy - 24 * s, s)}`;
