  const tcrClusters = [-20, -8, 5, 18].map((y, index) => `<g class="asset-tcell-tcr-cluster" data-cluster-index="${index}"><circle cx="${fmt(cx + 25 * s)}" cy="${fmt(cy + y * s)}" r="${fmt(2.2 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(0.9 * s)}"/><path d="M${fmt(cx + 28 * s)},${fmt(cy + y * s)} h${fmt(7 * s)} M${fmt(cx + 31.5 * s)},${fmt(cy + (y - 3) * s)} v${fmt(6 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-linecap="round"/></g>`).join("");
