  const corticalArc = `<path class="asset-tcell-cortical-arc" d="M${fmt(cx - 28 * s)},${fmt(cy + 16 * s)} C${fmt(cx - 9 * s)},${fmt(cy + 5 * s)} ${fmt(cx + 11 * s)},${fmt(cy + 14 * s)} ${fmt(cx + 28 * s)},${fmt(cy + 2 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.75 * s)}" stroke-linecap="round" opacity="0.54"/>`;
