  const lobules = [[-27, -13, 16, 8], [6, -17, 18, 9], [25, 3, 15, 8], [-16, 11, 18, 8]].map(([x, y, rx, ry], index) => `<ellipse class="asset-tissue-region-boundary" data-region-index="${index}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt(rx * s)}" ry="${fmt(ry * s)}" fill="${index % 2 ? palette.secondary : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(0.95 * s)}" opacity="${fmt(index % 2 ? 0.28 : 0.34)}" transform="rotate(${index * 17 - 12} ${fmt(cx + x * s)} ${fmt(cy + y * s)})"/>`).join("");
  const capillary = `<path class="asset-tissue-capillary" d="M${fmt(cx - 42 * s)},${fmt(cy + 13 * s)} C${fmt(cx - 22 * s)},${fmt(cy - 4 * s)} ${fmt(cx + 7 * s)},${fmt(cy + 25 * s)} ${fmt(cx + 40 * s)},${fmt(cy + 2 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(1.3 * s)}" opacity="0.34" stroke-linecap="round"/><circle class="asset-tissue-capillary" cx="${fmt(cx - 39 * s)}" cy="${fmt(cy + 11 * s)}" r="${fmt(2.8 * s)}" fill="${palette.stroke}" opacity="0.31"/><circle class="asset-tissue-capillary" cx="${fmt(cx + 38 * s)}" cy="${fmt(cy + 3 * s)}" r="${fmt(2.6 * s)}" fill="${palette.stroke}" opacity="0.27"/>`;
  const cells = [[-34, -18], [-21, -25], [-6, -21], [11, -18], [29, -11], [-29, -3], [-13, 0], [5, 1], [24, 8], [-17, 14], [2, 17], [18, 18]].map(([x, y], index) => `<ellipse class="asset-tissue-nucleus" data-nucleus-index="${index}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" rx="${fmt((index % 2 ? 3.2 : 4.1) * s)}" ry="${fmt((index % 3 ? 1.9 : 2.3) * s)}" fill="${palette.accent}" opacity="${fmt(index % 2 ? 0.52 : 0.69)}" transform="rotate(${index * 31} ${fmt(cx + x * s)} ${fmt(cy + y * s)})"/>`).join("");
