function pooledScreen(cx, cy, s, palette) {
  const wells = [];
  for (let row = 0; row < 4; row += 1) {
    for (let col = 0; col < 5; col += 1) {
      wells.push(`<circle cx="${fmt(cx - 29 * s + col * 14 * s)}" cy="${fmt(cy - 19 * s + row * 13 * s)}" r="${fmt(4.2 * s)}" fill="${(row + col) % 3 ? palette.secondary : palette.accent}" stroke="${palette.accent}" stroke-width="${fmt(0.9 * s)}" opacity="${(row + col) % 3 ? 0.68 : 0.92}"/>`);
    }
  }
  return `${baseLayer(cx, cy, s, palette, "panel")}<rect x="${fmt(cx - 45 * s)}" y="${fmt(cy - 34 * s)}" width="${fmt(90 * s)}" height="${fmt(68 * s)}" rx="${fmt(12 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}" filter="url(#asset-soft-shadow)"/>${wells.join("")}<path d="M${fmt(cx + 25 * s)},${fmt(cy + 26 * s)} l${fmt(16 * s)},${fmt(15 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(3 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx + 18 * s)}" cy="${fmt(cy + 19 * s)}" r="${fmt(13 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.3 * s)}"/>`;
}

function arrayedScreen(cx, cy, s, palette) {
  const wells = [];
  for (let row = 0; row < 3; row += 1) {
    for (let col = 0; col < 4; col += 1) {
      const hit = row === 1 && col === 2;
      wells.push(`<rect x="${fmt(cx - 34 * s + col * 18 * s)}" y="${fmt(cy - 24 * s + row * 17 * s)}" width="${fmt(12 * s)}" height="${fmt(12 * s)}" rx="${fmt(3 * s)}" fill="${hit ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}" opacity="${hit ? 0.96 : 0.62}"/>`);
    }
  }
  return `${baseLayer(cx, cy, s, palette, "panel")}<rect x="${fmt(cx - 46 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(92 * s)}" height="${fmt(70 * s)}" rx="${fmt(12 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}" filter="url(#asset-soft-shadow)"/>${wells.join("")}<path d="M${fmt(cx + 20 * s)},${fmt(cy + 23 * s)} l${fmt(12 * s)},${fmt(12 * s)} l${fmt(18 * s)},${fmt(-25 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.8 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`;
}

