  const check = `<g class="asset-target-validation-check"><circle cx="${fmt(cx + 40 * s)}" cy="${fmt(cy - 35 * s)}" r="${fmt(14 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}"/><path d="M${fmt(cx + 32 * s)},${fmt(cy - 35 * s)} l${fmt(6 * s)},${fmt(6 * s)} l${fmt(12 * s)},${fmt(-15 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.5 * s)}" stroke-linecap="round" stroke-linejoin="round"/></g>`;
  const evidence = `<path class="asset-target-validation-evidence-link" d="M${fmt(cx - 21 * s)},${fmt(cy - 35 * s)} C${fmt(cx - 3 * s)},${fmt(cy - 53 * s)} ${fmt(cx + 19 * s)},${fmt(cy - 52 * s)} ${fmt(cx + 32 * s)},${fmt(cy - 42 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.9 * s)}" stroke-dasharray="${fmt(4 * s)} ${fmt(3 * s)}" stroke-linecap="round"/>`;
