  const confidenceMeter = `<g class="asset-target-validation-confidence-meter"><rect x="${fmt(cx - 45 * s)}" y="${fmt(cy + 31 * s)}" width="${fmt(70 * s)}" height="${fmt(15 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.05 * s)}"/><path d="M${fmt(cx - 37 * s)},${fmt(cy + 38.5 * s)} h${fmt(43 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx + 12 * s)}" cy="${fmt(cy + 38.5 * s)}" r="${fmt(3.2 * s)}" fill="${palette.accent}"/></g>`;
  const orthogonalEvidence = `<g class="asset-target-validation-orthogonal-evidence"><rect x="${fmt(cx + 25 * s)}" y="${fmt(cy + 3 * s)}" width="${fmt(34 * s)}" height="${fmt(24 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/><path d="M${fmt(cx + 32 * s)},${fmt(cy + 16 * s)} h${fmt(19 * s)} M${fmt(cx + 42 * s)},${fmt(cy + 8 * s)} v${fmt(16 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}" stroke-linecap="round" opacity="0.72"/></g>`;
