function selectivityPanelAsset(cx, cy, s, palette) {
  const panel = `<rect class="asset-selectivity-panel-frame" x="${fmt(cx - 52 * s)}" y="${fmt(cy - 37 * s)}" width="${fmt(104 * s)}" height="${fmt(74 * s)}" rx="${fmt(14 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.1 * s)}"/>`;
  const cells = Array.from({ length: 20 }, (_, index) => {
    const col = index % 5;
    const row = Math.floor(index / 5);
    const target = index === 2;
    const offTarget = [8, 14].includes(index);
    const x = cx - 37 * s + col * 18 * s;
    const y = cy - 20 * s + row * 14 * s;
    return `<rect class="asset-selectivity-matrix-cell ${target ? "asset-selectivity-target-cell" : offTarget ? "asset-selectivity-offtarget-cell" : ""}" x="${fmt(x - 6 * s)}" y="${fmt(y - 5 * s)}" width="${fmt(12 * s)}" height="${fmt(10 * s)}" rx="${fmt(3 * s)}" fill="${target ? palette.accent : offTarget ? palette.secondary : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(0.8 * s)}" opacity="${target ? 0.94 : offTarget ? 0.7 : 0.58}"/>`;
  }).join("");
  const targetBadge = `<g class="asset-selectivity-target-badge"><circle cx="${fmt(cx + 42 * s)}" cy="${fmt(cy - 31 * s)}" r="${fmt(13 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}"/><path d="M${fmt(cx + 35 * s)},${fmt(cy - 31 * s)} l${fmt(5 * s)},${fmt(5 * s)} l${fmt(10 * s)},${fmt(-13 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2 * s)}" stroke-linecap="round" stroke-linejoin="round"/></g>`;
  const ratio = `<g class="asset-selectivity-ratio"><rect x="${fmt(cx - 45 * s)}" y="${fmt(cy + 27 * s)}" width="${fmt(39 * s)}" height="${fmt(14 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.05 * s)}"/><path d="M${fmt(cx - 38 * s)},${fmt(cy + 34 * s)} h${fmt(9 * s)} M${fmt(cx - 24 * s)},${fmt(cy + 34 * s)} h${fmt(12 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.3 * s)}" stroke-linecap="round"/></g>`;
  const targetBeam = `<path class="asset-selectivity-target-beam" d="M${fmt(cx + 3 * s)},${fmt(cy - 35 * s)} V${fmt(cy + 19 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-dasharray="${fmt(3 * s)} ${fmt(3 * s)}" opacity="0.56"/><path class="asset-selectivity-target-beam" d="M${fmt(cx - 45 * s)},${fmt(cy - 12 * s)} H${fmt(cx + 43 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-dasharray="${fmt(3 * s)} ${fmt(3 * s)}" opacity="0.4"/>`;
  const offTargetWarning = `<g class="asset-selectivity-offtarget-warning"><path d="M${fmt(cx + 33 * s)},${fmt(cy + 18 * s)} l${fmt(10 * s)},${fmt(17 * s)} h${fmt(-20 * s)} Z" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/><circle cx="${fmt(cx + 33 * s)}" cy="${fmt(cy + 30 * s)}" r="${fmt(1.3 * s)}" fill="${palette.accent}"/></g>`;
  return `${baseLayer(cx, cy, s, palette, "panel")}<g filter="url(#asset-soft-shadow)">${panel}<path d="M${fmt(cx - 44 * s)},${fmt(cy - 28 * s)} h${fmt(63 * s)}" stroke="#ffffff" stroke-width="${fmt(1.4 * s)}" opacity="0.46" stroke-linecap="round"/>${targetBeam}${cells}${targetBadge}${ratio}${offTargetWarning}</g>`;
}

