    const molecule = `<path class="asset-sar-table-molecule" d="M${fmt(cx - 40 * s)},${fmt(cy + (y - 5) * s)} l${fmt(7 * s)},${fmt(-4 * s)} l${fmt(7 * s)},${fmt(4 * s)} v${fmt(8 * s)} l${fmt(-7 * s)},${fmt(4 * s)} l${fmt(-7 * s)},${fmt(-4 * s)} Z" fill="${row === 1 ? palette.accent : "#ffffff"}" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}"/>`;
    const bars = `<path class="asset-sar-table-potency-bar" d="M${fmt(cx - 20 * s)},${fmt(cy + y * s)} h${fmt((18 + row * 10) * s)}" stroke="${row === 2 ? palette.accent : palette.stroke}" stroke-width="${fmt(3 * s)}" stroke-linecap="round" opacity="${row === 2 ? 0.92 : 0.58}"/><path d="M${fmt(cx + 22 * s)},${fmt(cy + y * s)} h${fmt((20 - row * 4) * s)}" stroke="${palette.secondary}" stroke-width="${fmt(3 * s)}" stroke-linecap="round" opacity="0.72"/>`;
