function medicinalChemistryCycleAsset(cx, cy, s, palette) {
  const orbit = `<path class="asset-medchem-cycle-orbit" d="M${fmt(cx - 36 * s)},${fmt(cy - 5 * s)} C${fmt(cx - 34 * s)},${fmt(cy - 36 * s)} ${fmt(cx + 16 * s)},${fmt(cy - 43 * s)} ${fmt(cx + 34 * s)},${fmt(cy - 17 * s)} C${fmt(cx + 51 * s)},${fmt(cy + 10 * s)} ${fmt(cx + 15 * s)},${fmt(cy + 42 * s)} ${fmt(cx - 17 * s)},${fmt(cy + 31 * s)} C${fmt(cx - 45 * s)},${fmt(cy + 22 * s)} ${fmt(cx - 51 * s)},${fmt(cy - 15 * s)} ${fmt(cx - 36 * s)},${fmt(cy - 5 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.5 * s)}" stroke-linecap="round" stroke-dasharray="${fmt(6 * s)} ${fmt(4 * s)}"/>`;
  const arrows = `<path class="asset-medchem-cycle-arrow" d="M${fmt(cx + 35 * s)},${fmt(cy - 17 * s)} l${fmt(-2 * s)},${fmt(12 * s)} l${fmt(12 * s)},${fmt(-3 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round" stroke-linejoin="round"/><path class="asset-medchem-cycle-arrow" d="M${fmt(cx - 18 * s)},${fmt(cy + 31 * s)} l${fmt(12 * s)},${fmt(-1 * s)} l${fmt(-5 * s)},${fmt(11 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round" stroke-linejoin="round"/>`;
  const molecule = `<g class="asset-medchem-cycle-molecule"><path d="M${fmt(cx - 12 * s)},${fmt(cy - 8 * s)} l${fmt(12 * s)},${fmt(-8 * s)} l${fmt(13 * s)},${fmt(8 * s)} v${fmt(16 * s)} l${fmt(-13 * s)},${fmt(8 * s)} l${fmt(-12 * s)},${fmt(-8 * s)} Z" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(1.8 * s)}"/><circle cx="${fmt(cx + 20 * s)}" cy="${fmt(cy - 17 * s)}" r="${fmt(5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/></g>`;
  const steps = [
    [-39, -35, "design"],
    [29, -37, "make"],
    [34, 28, "test"],
    [-42, 24, "learn"]
  ].map(([x, y, label]) => `<g class="asset-medchem-cycle-step" data-step="${label}"><rect x="${fmt(cx + (x - 13) * s)}" y="${fmt(cy + (y - 7) * s)}" width="${fmt(26 * s)}" height="${fmt(14 * s)}" rx="${fmt(7 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1 * s)}"/><path d="M${fmt(cx + (x - 7) * s)},${fmt(cy + y * s)} h${fmt(14 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.25 * s)}" stroke-linecap="round"/></g>`).join("");
  const centralCard = `<rect class="asset-medchem-cycle-central-card" x="${fmt(cx - 24 * s)}" y="${fmt(cy - 24 * s)}" width="${fmt(48 * s)}" height="${fmt(48 * s)}" rx="${fmt(13 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}" opacity="0.72"/>`;
  const decisionGate = `<g class="asset-medchem-cycle-decision-gate"><path d="M${fmt(cx + 42 * s)},${fmt(cy + 9 * s)} l${fmt(13 * s)},${fmt(13 * s)} l${fmt(-13 * s)},${fmt(13 * s)} l${fmt(-13 * s)},${fmt(-13 * s)} Z" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}"/><path d="M${fmt(cx + 36 * s)},${fmt(cy + 22 * s)} h${fmt(13 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.35 * s)}" stroke-linecap="round"/></g>`;
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${orbit}${arrows}${steps}${centralCard}${molecule}${decisionGate}<circle cx="${fmt(cx)}" cy="${fmt(cy)}" r="${fmt(30 * s)}" fill="url(#asset-body-depth)" opacity="0.18"/></g>`;
}

