  const dose = `<g class="asset-efficacy-model-dose"><rect x="${fmt(cx - 48 * s)}" y="${fmt(cy - 41 * s)}" width="${fmt(34 * s)}" height="${fmt(17 * s)}" rx="${fmt(8 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/><path d="M${fmt(cx - 40 * s)},${fmt(cy - 33 * s)} h${fmt(18 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}" stroke-linecap="round"/></g>`;
