  const treatmentArm = `<g class="asset-efficacy-model-treatment-arm"><circle cx="${fmt(cx - 41 * s)}" cy="${fmt(cy - 9 * s)}" r="${fmt(5 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}"/><circle cx="${fmt(cx - 31 * s)}" cy="${fmt(cy - 16 * s)}" r="${fmt(5 * s)}" fill="${palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.2 * s)}"/><path d="M${fmt(cx - 37 * s)},${fmt(cy - 12 * s)} C${fmt(cx - 25 * s)},${fmt(cy - 29 * s)} ${fmt(cx - 8 * s)},${fmt(cy - 25 * s)} ${fmt(cx + 1 * s)},${fmt(cy - 15 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.55 * s)}" stroke-dasharray="${fmt(3 * s)} ${fmt(3 * s)}" stroke-linecap="round"/></g>`;
  const responseBadge = `<g class="asset-efficacy-model-response-badge"><rect x="${fmt(cx + 18 * s)}" y="${fmt(cy + 21 * s)}" width="${fmt(44 * s)}" height="${fmt(18 * s)}" rx="${fmt(9 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.1 * s)}"/><path d="M${fmt(cx + 27 * s)},${fmt(cy + 30 * s)} h${fmt(9 * s)} M${fmt(cx + 42 * s)},${fmt(cy + 30 * s)} h${fmt(10 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.25 * s)}" stroke-linecap="round"/></g>`;
