  const cutpoint = `<g class="asset-biomarker-response-cutpoint"><path d="M${fmt(cx + 25 * s)},${fmt(cy + 22 * s)} V${fmt(cy - 21 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.15 * s)}" stroke-dasharray="${fmt(3 * s)} ${fmt(3 * s)}" opacity="0.52"/><rect x="${fmt(cx + 28 * s)}" y="${fmt(cy - 3 * s)}" width="${fmt(25 * s)}" height="${fmt(13 * s)}" rx="${fmt(6 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(0.9 * s)}" opacity="0.94"/></g>`;
  const responderBand = `<path class="asset-biomarker-response-responder-band" d="M${fmt(cx + 12 * s)},${fmt(cy + 18 * s)} C${fmt(cx + 20 * s)},${fmt(cy + 4 * s)} ${fmt(cx + 28 * s)},${fmt(cy - 4 * s)} ${fmt(cx + 41 * s)},${fmt(cy - 22 * s)} L${fmt(cx + 41 * s)},${fmt(cy - 13 * s)} C${fmt(cx + 29 * s)},${fmt(cy - 2 * s)} ${fmt(cx + 23 * s)},${fmt(cy + 8 * s)} ${fmt(cx + 12 * s)},${fmt(cy + 22 * s)} Z" fill="${palette.secondary}" opacity="0.32"/>`;
  const sampleDots = `<g class="asset-biomarker-response-sample-dots">${[-9, -2, 7, 16].map((x, index) => `<circle cx="${fmt(cx + x * s)}" cy="${fmt(cy + (23 - index * 7) * s)}" r="${fmt(2.2 * s)}" fill="${index > 1 ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(0.7 * s)}" opacity="0.86"/>`).join("")}</g>`;
