  const gate = `<g class="asset-ind-package-readiness-gate"><rect x="${fmt(cx + 14 * s)}" y="${fmt(cy + 17 * s)}" width="${fmt(46 * s)}" height="${fmt(22 * s)}" rx="${fmt(10 * s)}" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.3 * s)}"/><path d="M${fmt(cx + 24 * s)},${fmt(cy + 28 * s)} h${fmt(22 * s)} M${fmt(cx + 41 * s)},${fmt(cy + 23 * s)} l${fmt(6 * s)},${fmt(5 * s)} l${fmt(-6 * s)},${fmt(5 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(1.65 * s)}" stroke-linecap="round" stroke-linejoin="round"/></g>`;
