function instrumentTones(palette) {
  if (palette.styleProfile === "publication-line") {
    return {
      halo: "#ffffff",
      body: "#ffffff",
      body2: "#ffffff",
      panel: "#ffffff",
      inset: "#ffffff",
      dark: "#111827",
      glass: "#ffffff",
      accent: "#111827",
      led: "#111827",
      metal: "#ffffff",
      stroke: "#111827",
      text: "#111827"
    };
  }
  if (palette.styleProfile === "dark-talk") {
    return {
      halo: "#172033",
      body: "#263241",
      body2: "#3a4657",
      panel: "#111827",
      inset: "#0b1120",
      dark: "#020617",
      glass: "#13283d",
      accent: "#38bdf8",
      led: "#67e8f9",
      metal: "#64748b",
      stroke: "#e2e8f0",
      text: "#f8fafc"
    };
  }
  if (palette.styleProfile === "risk-warning") {
    return {
      halo: "#fff7ed",
      body: "#f8fafc",
      body2: "#e2e8f0",
      panel: "#ffffff",
      inset: "#1f2937",
      dark: "#111827",
      glass: "#fee2e2",
      accent: "#dc2626",
      led: "#f97316",
      metal: "#cbd5e1",
      stroke: "#7f1d1d",
      text: "#111827"
    };
  }
  return {
    halo: "#eef6fb",
    body: "#f8fafc",
    body2: "#d8dee8",
    panel: "#ffffff",
    inset: "#202936",
    dark: "#111827",
    glass: "#dbeafe",
    accent: palette.accent,
    led: "#38bdf8",
    metal: "#cbd5e1",
    stroke: "#415166",
    text: "#0f172a"
  };
}

function instrumentBaseLayer(cx, cy, s, palette, shape = "panel") {
  const tones = instrumentTones(palette);
  return baseLayer(cx, cy, s, { ...palette, fill: tones.body, secondary: tones.halo, stroke: tones.stroke, accent: tones.accent }, shape);
}

function instrumentGloss(cx, cy, s, tones, width = 80, y = -32, curve = 10) {
  return `<path class="asset-instrument-material-highlight" d="M${fmt(cx - width * 0.5 * s)},${fmt(cy + y * s)} C${fmt(cx - width * 0.24 * s)},${fmt(cy + (y - curve) * s)} ${fmt(cx + width * 0.22 * s)},${fmt(cy + (y - curve) * s)} ${fmt(cx + width * 0.5 * s)},${fmt(cy + y * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.6 * s)}" opacity="${tones.body === "#ffffff" ? "0.18" : "0.62"}" stroke-linecap="round"/>`;
}

function instrumentSideRim(cx, cy, s, tones, x = 42, y1 = -24, y2 = 34) {
  return `<path class="asset-instrument-side-rim" d="M${fmt(cx + x * s)},${fmt(cy + y1 * s)} v${fmt((y2 - y1) * s)}" stroke="${tones.metal}" stroke-width="${fmt(1.6 * s)}" opacity="0.78" stroke-linecap="round"/>`;
}

function instrumentFeet(cx, cy, s, tones, left = -34, right = 34, y = 49) {
  return `<path class="asset-instrument-foot" d="M${fmt(cx + left * s)},${fmt(cy + y * s)} v${fmt(6 * s)} M${fmt(cx + right * s)},${fmt(cy + y * s)} v${fmt(6 * s)}" stroke="${tones.dark}" stroke-width="${fmt(1.25 * s)}" stroke-linecap="round" opacity="0.5"/>`;
}

function instrumentMicroScrews(points, cx, cy, s, tones, className = "asset-instrument-fastener") {
  return points.map(([x, y]) => `<circle class="${className}" cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" r="${fmt(1.65 * s)}" fill="${tones.dark}" opacity="${tones.body === "#ffffff" ? "0.2" : "0.58"}"/>`).join("");
}

function sequencerAssetV3(cx, cy, s, palette) {
  const t = instrumentTones(palette);
  const lanes = [-28, -18, -8, 2, 12, 22, 32].map((x, index) => `<path class="asset-sequencer-run-lane" d="M${fmt(cx + x * s)},${fmt(cy - 18 * s)} v${fmt(15 * s)}" stroke="${index % 2 ? t.stroke : t.accent}" stroke-width="${fmt(1.15 * s)}" stroke-linecap="round" opacity="${index % 2 ? 0.38 : 0.72}"/>`).join("");
  const body = `<g class="asset-sequencer-body"><path d="M${fmt(cx - 50 * s)},${fmt(cy - 39 * s)} h${fmt(100 * s)} q${fmt(9 * s)},0 ${fmt(11 * s)},${fmt(11 * s)} v${fmt(65 * s)} q0,${fmt(10 * s)} ${fmt(-10 * s)},${fmt(10 * s)} h${fmt(-100 * s)} q${fmt(-10 * s)},0 ${fmt(-10 * s)},${fmt(-10 * s)} v${fmt(-65 * s)} q0,${fmt(-11 * s)} ${fmt(9 * s)},${fmt(-11 * s)} Z" fill="${t.body}" stroke="${t.stroke}" stroke-width="${fmt(2.15 * s)}"/><path class="asset-sequencer-side-panel" d="M${fmt(cx + 40 * s)},${fmt(cy - 38 * s)} q${fmt(12 * s)},0 ${fmt(12 * s)},${fmt(12 * s)} v${fmt(62 * s)} q0,${fmt(9 * s)} ${fmt(-9 * s)},${fmt(9 * s)} h${fmt(-18 * s)} q${fmt(7 * s)},${fmt(-7 * s)} ${fmt(7 * s)},${fmt(-16 * s)} v${fmt(-46 * s)} q0,${fmt(-11 * s)} ${fmt(-4 * s)},${fmt(-20 * s)} Z" fill="${t.body2}" stroke="${t.metal}" stroke-width="${fmt(1.2 * s)}"/><path d="M${fmt(cx - 42 * s)},${fmt(cy - 35 * s)} C${fmt(cx - 12 * s)},${fmt(cy - 45 * s)} ${fmt(cx + 14 * s)},${fmt(cy - 45 * s)} ${fmt(cx + 36 * s)},${fmt(cy - 34 * s)}" fill="none" stroke="#ffffff" stroke-width="${fmt(1.8 * s)}" opacity="0.7" stroke-linecap="round"/></g>`;
  const screen = `<g class="asset-sequencer-screen"><rect x="${fmt(cx - 39 * s)}" y="${fmt(cy - 31 * s)}" width="${fmt(78 * s)}" height="${fmt(30 * s)}" rx="${fmt(4 * s)}" fill="${t.panel}" stroke="${t.metal}" stroke-width="${fmt(1.2 * s)}"/><circle class="asset-sequencer-touch-start" cx="${fmt(cx)}" cy="${fmt(cy - 16 * s)}" r="${fmt(10 * s)}" fill="${t.glass}" stroke="${t.accent}" stroke-width="${fmt(1 * s)}" opacity="0.82"/><path d="M${fmt(cx - 5 * s)},${fmt(cy - 16 * s)} h${fmt(10 * s)} M${fmt(cx)},${fmt(cy - 21 * s)} v${fmt(10 * s)}" stroke="${t.accent}" stroke-width="${fmt(1 * s)}" stroke-linecap="round" opacity="0.72"/>${lanes}</g>`;
  const ledBand = `<rect class="asset-sequencer-led-band" x="${fmt(cx - 51 * s)}" y="${fmt(cy + 6 * s)}" width="${fmt(102 * s)}" height="${fmt(17 * s)}" rx="${fmt(3 * s)}" fill="${t.led}" opacity="${palette.styleProfile === "publication-line" ? "0.08" : "0.34"}"/><path d="M${fmt(cx - 48 * s)},${fmt(cy + 7 * s)} h${fmt(96 * s)}" stroke="#ffffff" stroke-width="${fmt(1.2 * s)}" opacity="0.42"/>`;
  const door = `<g class="asset-sequencer-door"><rect x="${fmt(cx - 28 * s)}" y="${fmt(cy + 28 * s)}" width="${fmt(56 * s)}" height="${fmt(15 * s)}" rx="${fmt(4 * s)}" fill="${t.panel}" stroke="${t.metal}" stroke-width="${fmt(1.05 * s)}"/><path class="asset-sequencer-cartridge" d="M${fmt(cx - 21 * s)},${fmt(cy + 35 * s)} h${fmt(31 * s)}" stroke="${t.accent}" stroke-width="${fmt(1.55 * s)}" stroke-linecap="round"/><circle class="asset-sequencer-status-light" cx="${fmt(cx + 37 * s)}" cy="${fmt(cy + 35 * s)}" r="${fmt(4.2 * s)}" fill="${t.led}" stroke="${t.stroke}" stroke-width="${fmt(0.7 * s)}"/></g>`;
  const vents = Array.from({ length: 13 }, (_, i) => `<path class="asset-sequencer-vent asset-sequencer-vent-array" d="M${fmt(cx - 38 * s + i * 6.4 * s)},${fmt(cy + 51 * s)} v${fmt(6 * s)}" stroke="${t.dark}" stroke-width="${fmt(1.15 * s)}" stroke-linecap="round" opacity="0.46"/>`).join("");
  const polish = `${instrumentGloss(cx, cy, s, t, 86, -35, 9)}${instrumentSideRim(cx, cy, s, t, 43, -22, 33)}${instrumentFeet(cx, cy, s, t, -38, 38, 49)}${instrumentMicroScrews([[-44, -29], [44, -29], [-44, 39], [44, 39]], cx, cy, s, t)}`;
  return `${instrumentBaseLayer(cx, cy, s, palette, "panel")}<g filter="url(#asset-soft-shadow)">${body}${polish}${screen}${ledBand}${door}${vents}</g>`;
}

