  const warning = `<g class="asset-pathogen-sample-warning"><path d="M${fmt(cx + 34 * s)},${fmt(cy + 16 * s)} l${fmt(13 * s)},${fmt(23 * s)} h${fmt(-26 * s)} Z" fill="#ffffff" stroke="${palette.accent}" stroke-width="${fmt(1.45 * s)}" stroke-linejoin="round"/><path d="M${fmt(cx + 34 * s)},${fmt(cy + 25 * s)} v${fmt(7 * s)}" stroke="${palette.accent}" stroke-width="${fmt(1.5 * s)}" stroke-linecap="round"/><circle cx="${fmt(cx + 34 * s)}" cy="${fmt(cy + 35.5 * s)}" r="${fmt(1.2 * s)}" fill="${palette.accent}"/></g>`;
  return `${baseLayer(cx, cy, s, palette, "panel")}<g filter="url(#asset-soft-shadow)">${tube}${particles}${barcode}${warning}<path d="M${fmt(cx - 15 * s)},${fmt(cy - 27 * s)} h${fmt(30 * s)}" stroke="#ffffff" stroke-width="${fmt(1.55 * s)}" opacity="0.62" stroke-linecap="round"/></g>`;
