function dataStack(cx, cy, s, palette) {
  const decks = [-28, -11, 7].map((y, index) => {
    const w = (86 - index * 7) * s;
    const x = cx - w / 2 + index * 3 * s;
    const fill = index === 0 ? palette.fill : index === 1 ? palette.secondary : "#ffffff";
    return `<rect x="${fmt(x)}" y="${fmt(cy + y * s)}" width="${fmt(w)}" height="${fmt(31 * s)}" rx="${fmt(10 * s)}" fill="${fill}" stroke="${palette.stroke}" stroke-width="${fmt(1.8 * s)}" opacity="${index === 2 ? 0.96 : 1}"/>`;
  }).join("");
  const rows = [-20, -9, 2, 16, 27].map((y, index) => `<path d="M${fmt(cx - 29 * s)},${fmt(cy + y * s)} h${fmt((index % 2 ? 42 : 55) * s)}" stroke="${index === 4 ? palette.stroke : palette.accent}" stroke-width="${fmt((index === 4 ? 1.4 : 2) * s)}" stroke-linecap="round" opacity="${index === 4 ? 0.46 : 0.82}"/>`).join("");
  const sampleChips = [[-40, -33], [28, -30], [42, 22]].map(([x, y], index) => `<g class="asset-dataset-chip"><circle cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" r="${fmt((index === 1 ? 8 : 6.5) * s)}" fill="${index === 1 ? palette.accent : palette.secondary}" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}"/><path d="M${fmt(cx + (x - 3) * s)},${fmt(cy + y * s)} h${fmt(6 * s)} M${fmt(cx + x * s)},${fmt(cy + (y - 3) * s)} v${fmt(6 * s)}" stroke="#ffffff" stroke-width="${fmt(1.1 * s)}" stroke-linecap="round" opacity="0.84"/></g>`).join("");
  return `${baseLayer(cx, cy, s, palette, "panel")}<g filter="url(#asset-soft-shadow)">${decks}<path d="M${fmt(cx - 41 * s)},${fmt(cy - 27 * s)} C${fmt(cx - 8 * s)},${fmt(cy - 43 * s)} ${fmt(cx + 31 * s)},${fmt(cy - 38 * s)} ${fmt(cx + 47 * s)},${fmt(cy - 18 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(2.4 * s)}" stroke-linecap="round" opacity="0.56"/><rect x="${fmt(cx - 36 * s)}" y="${fmt(cy - 25 * s)}" width="${fmt(72 * s)}" height="${fmt(58 * s)}" rx="${fmt(13 * s)}" fill="url(#asset-glass-highlight)" opacity="0.36"/>${rows}${sampleChips}</g>`;
}

function modelBlock(cx, cy, s, palette, mode) {
  const layers = mode === "foundation" ? 5 : 3;
  const layerSvg = Array.from({ length: layers }, (_, i) => `<rect x="${fmt(cx - 35 * s + i * 15 * s)}" y="${fmt(cy - (22 - i * 2) * s)}" width="${fmt(16 * s)}" height="${fmt((44 - i * 4) * s)}" rx="${fmt(6 * s)}" fill="${i % 2 ? "#ffffff" : palette.secondary}" opacity="${i % 2 ? 0.7 : 0.95}" stroke="${palette.accent}" stroke-width="${fmt(1.4 * s)}"/>`).join("");
  const crown = mode === "foundation" ? `<path d="M${fmt(cx - 35 * s)},${fmt(cy - 33 * s)} h${fmt(70 * s)} M${fmt(cx - 32 * s)},${fmt(cy + 34 * s)} h${fmt(64 * s)}" stroke="${palette.accent}" stroke-width="${fmt(2.2 * s)}" stroke-linecap="round"/>` : "";
  return `${baseLayer(cx, cy, s, palette, "panel")}<rect x="${fmt(cx - 49 * s)}" y="${fmt(cy - 35 * s)}" width="${fmt(98 * s)}" height="${fmt(70 * s)}" rx="${fmt(17 * s)}" fill="${palette.fill}" stroke="${palette.stroke}" stroke-width="${fmt(2.2 * s)}" filter="url(#asset-soft-shadow)"/>${layerSvg}${crown}<circle cx="${fmt(cx - 39 * s)}" cy="${fmt(cy - 7 * s)}" r="${fmt(5 * s)}" fill="${palette.accent}"/><circle cx="${fmt(cx + 39 * s)}" cy="${fmt(cy + 10 * s)}" r="${fmt(5 * s)}" fill="${palette.accent}"/>`;
}

function neuralNetwork(cx, cy, s, palette) {
  const cols = [[-34, [-18, 0, 18]], [0, [-26, -8, 10, 28]], [35, [-15, 5, 25]]];
  const nodeSvg = cols.flatMap(([x, ys], colIndex) => ys.map((y) => `<circle cx="${fmt(cx + x * s)}" cy="${fmt(cy + y * s)}" r="${fmt((colIndex === 1 ? 5.5 : 6.5) * s)}" fill="${colIndex === 1 ? palette.secondary : palette.fill}" stroke="${palette.accent}" stroke-width="${fmt(1.8 * s)}"/>`)).join("");
  const edges = [];
  for (const y1 of cols[0][1]) for (const y2 of cols[1][1]) edges.push(`<path d="M${fmt(cx - 34 * s)},${fmt(cy + y1 * s)} L${fmt(cx)},${fmt(cy + y2 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.05 * s)}" opacity="0.34"/>`);
  for (const y1 of cols[1][1]) for (const y2 of cols[2][1]) edges.push(`<path d="M${fmt(cx)},${fmt(cy + y1 * s)} L${fmt(cx + 35 * s)},${fmt(cy + y2 * s)}" stroke="${palette.stroke}" stroke-width="${fmt(1.05 * s)}" opacity="0.34"/>`);
  return `${baseLayer(cx, cy, s, palette)}<g filter="url(#asset-soft-shadow)">${edges.join("")}${nodeSvg}</g>`;
}

