  const vessels = `<path class="asset-heart-aorta" d="M${fmt(cx - 3 * s)},${fmt(cy - 29 * s)} C${fmt(cx - 13 * s)},${fmt(cy - 54 * s)} ${fmt(cx + 24 * s)},${fmt(cy - 58 * s)} ${fmt(cx + 27 * s)},${fmt(cy - 34 * s)} C${fmt(cx + 39 * s)},${fmt(cy - 47 * s)} ${fmt(cx + 51 * s)},${fmt(cy - 35 * s)} ${fmt(cx + 38 * s)},${fmt(cy - 22 * s)}" fill="none" stroke="${palette.stroke}" stroke-width="${fmt(5.3 * s)}" stroke-linecap="round"/><path d="M${fmt(cx - 22 * s)},${fmt(cy - 27 * s)} C${fmt(cx - 29 * s)},${fmt(cy - 44 * s)} ${fmt(cx - 13 * s)},${fmt(cy - 51 * s)} ${fmt(cx - 5 * s)},${fmt(cy - 35 * s)} M${fmt(cx + 16 * s)},${fmt(cy - 27 * s)} C${fmt(cx + 32 * s)},${fmt(cy - 42 * s)} ${fmt(cx + 43 * s)},${fmt(cy - 27 * s)} ${fmt(cx + 28 * s)},${fmt(cy - 13 * s)} M${fmt(cx + 2 * s)},${fmt(cy - 32 * s)} v${fmt(-16 * s)}" fill="none" stroke="${palette.accent}" stroke-width="${fmt(3 * s)}" stroke-linecap="round"/>`;
